+++ de-webalizer-2.1.5/Makefile	Mon Oct  9 22:31:13 2000
@@ -5,52 +5,65 @@
 # $FreeBSD: ports/german/webalizer/Makefile,v 1.16 2000/09/05 02:12:33 steve Exp $

 PORTNAME=	webalizer
-PORTVERSION=	1.30.4
+PORTVERSION=	2.1.5
